input.command:
foreach ($f in 'website/docs/contributing/segment.mdx','website/docs/configuration/templates.mdx') {
  $head = (git show ("HEAD:" + $f)) -split "`n"
  $queue = [System.Collections.Generic.Queue[string]]::new()
  foreach ($h in $head) { if ($h -match "`t") { $queue.Enqueue($h) } }
  $cur = Get-Content $f
  $restored = 0
  for ($i=0; $i -lt $cur.Count; $i++) {
    if ($queue.Count -eq 0) { break }
    $cand = $queue.Peek()
    if (($cand -replace "`t",' ') -eq $cur[$i]) { $cur[$i] = $cand; $queue.Dequeue() | Out-Null; $restored++ }
  }
  Set-Content -Path $f -Value ($cur -join "`n") -NoNewline -Encoding utf8
  Add-Content -Path $f -Value "" -Encoding utf8 -NoNewline
  "{0}: restored {1}, unmatched {2}" -f $f, $restored, $queue.Count
}
